const today = new Date();
today.setHours(0, 0, 0, 0);

return items
  .map(item => {
    const expiryTimestamp = item.json.properties?.contract_expiry_date?.value;
    if (!expiryTimestamp) return null;

    const expiryDate = new Date(Number(expiryTimestamp));
    expiryDate.setHours(0, 0, 0, 0);

    const diffDays = Math.round(
      (expiryDate - today) / (1000 * 60 * 60 * 24)
    );

    return {
      json: {
        dealId: item.json.dealId,
        dealName: item.json.properties?.dealname?.value || "No Name",
        expiryDate: expiryDate.toISOString().split("T")[0],
        daysLeft: diffDays
      }
    };
  })
  .filter(item => item && [30, 60, 90].includes(item.json.daysLeft));

